        { referencia: "Eclesiastes 7:14", texto: "No dia da prosperidade goza do bem, mas no dia da adversidade considera." },
        { referencia: "Eclesiastes 7:16-18", texto: "Não sejas demasiadamente justo... não sejas demasiadamente ímpio... o que teme a Deus acaba com ambas." },
        { referencia: "Eclesiastes 7:20", texto: "Não há homem justo sobre a terra, que faça o bem e nunca peque." }
